BEGIN;
-- Chunk C: final exam quiz + sections + questions + answers (part 2/3)
INSERT INTO quiz_answers (question_id, answer_letter, answer_text, is_correct, explanation, display_order)
SELECT qq.id, v.answer_letter, v.answer_text, v.is_correct, v.explanation, v.display_order
FROM (VALUES
  (21, 'A', 'Good / Fair / Poor / Failed', FALSE, 'Not the standard used in this book.', 1),
  (21, 'B', 'Monitor / Maintenance Needed / Repair Recommended / Urgent or Escalate', TRUE, 'Standard scale. Reference: Chapter 12, all system chapters.', 2),
  (21, 'C', 'Pass / Fail / Conditional / Re-inspect', FALSE, 'Not the standard used in this book.', 3),
  (21, 'D', 'Green / Yellow / Red / Black', FALSE, 'Color codes aren''t the standard rating system.', 4),
  (22, 'A', 'Customer, company, and warranty system', TRUE, 'Three audiences for documentation. Reference: Chapter 12.', 1),
  (22, 'B', 'Sales, production, and accounting', FALSE, 'These are internal departments, not the documented audiences.', 2),
  (22, 'C', 'Customer, insurance, and IRS', FALSE, 'Not the standard framing.', 3),
  (22, 'D', 'Rep, customer, and HOA', FALSE, 'Not the standard framing.', 4),
  (23, 'A', 'Optional decoration', FALSE, 'Reference scale is required for size-relevant shots.', 1),
  (23, 'B', 'An object included to indicate size — like a business card, tape measure, or chalk mark', TRUE, 'Standard photo standard. Reference: Chapter 12, Module 7.', 2),
