  (47, 'C', 'Full replacement', TRUE, 'End-of-life PVC with chronic ponding. Reference: Chapter 5.', 3),
  (47, 'D', 'Acrylic coating to restore flexibility', FALSE, 'Coatings don''t restore flexibility to aged PVC.', 4),
  (48, 'A', 'Silicone restoration coating only', FALSE, 'Coatings don''t fix ponding.', 1),
  (48, 'B', 'SPF (with taper) or replacement with tapered insulation; both address the slope, neither is cheapest by total cost but both actually solve the problem', TRUE, 'Both address slope. Reference: Chapter 16.', 2),
  (48, 'C', 'Add another drain anywhere on the roof', FALSE, 'Drain placement requires engineering analysis.', 3),
  (48, 'D', 'Apply two coats of acrylic coating', FALSE, 'Coatings don''t fix ponding.', 4),
  (49, 'A', 'Apply the rejuvenation as requested', FALSE, 'Outside qualifying window; rejuvenation won''t perform.', 1),
  (49, 'B', 'Apply rejuvenation but with a higher application rate', FALSE, 'Application rate doesn''t fix qualifying-window issues.', 2),
  (49, 'C', 'Decline to propose rejuvenation, explain why the roof does not qualify, and recommend an honest alternative', TRUE, 'End-of-life shingle outside qualifying window. Reference: Chapter 4, Module 5.', 3),
  (49, 'D', 'Offer rejuvenation only if the customer signs a waiver', FALSE, 'Waivers don''t make a non-qualifying roof qualify.', 4),
  (50, 'A', 'Quote the project as torch-down to capture the work', FALSE, 'USA Flat Roof installs only self-adhered.', 1),
  (50, 'B', 'Explain that USA Flat Roof installs only self-adhered modified bitumen, the reasoning, and offer to quote self-adhered as an alternative', TRUE, 'Honest positioning. Reference: Chapter 6.', 2),
  (50, 'C', 'Decline the project without explanation', FALSE, 'Explanation is part of honest engagement.', 3),
  (50, 'D', 'Propose silicone coating instead', FALSE, 'Silicone isn''t a replacement for new modified bitumen.', 4),
