  (54, 'D', '''I''ll check with the manufacturer and call you back''', FALSE, 'Document review is part of the conversation, not deferral.', 4),
  (55, 'A', 'Given a verbal price to close the deal', FALSE, 'Verbal pricing creates problems.', 1),
  (55, 'B', 'Told the price will come in the written proposal so the scope and price match', TRUE, 'Honest framework. Reference: Module 11.', 2),
