  (56, 'A', 'Recommend the cheapest option regardless of fit', FALSE, 'Cheapest option may not perform.', 1),
  (56, 'B', 'Confirm that the cheapest option performs for their roof; if it doesn''t, name that and offer alternatives', TRUE, 'Honest engagement. Reference: Module 11, Chapter 13.', 2),
  (56, 'C', 'Decline the project', FALSE, 'Engagement is appropriate.', 3),
  (56, 'D', 'Pressure the customer toward a higher-cost option', FALSE, 'Pressure tactics damage trust.', 4),
  (57, 'A', 'Sell the most expensive option since it''s requested', FALSE, 'Overselling on a roof that doesn''t need it is dishonest.', 1),
  (57, 'B', 'Recommend what the roof actually needs, not the most expensive option', TRUE, 'Don''t upsell. Reference: Module 11, Chapter 13.', 2),
  (57, 'C', 'Add unnecessary scope to justify a higher price', FALSE, 'Scope inflation is dishonest.', 3),
  (57, 'D', 'Refer the customer elsewhere', FALSE, 'Engagement is appropriate.', 4),
  (58, 'A', 'Defer to the customer''s report', FALSE, 'Observations supplement reports.', 1),
  (58, 'B', 'Tell the customer they''re wrong', FALSE, 'Confrontational framing damages trust.', 2),
  (58, 'C', 'Document what was observed, ask for documentation, and reconcile any discrepancy honestly', TRUE, 'Honest framework. Reference: Chapter 17, Chapter 18.', 3),
  (58, 'D', 'Quote work based on the customer''s report', FALSE, 'Quoting on unverified information creates problems.', 4),
  (59, 'A', 'Confirm the other contractor is correct', FALSE, 'Coverage isn''t unlimited.', 1),
  (59, 'B', 'Bash the other contractor', FALSE, 'Bashing competitors is unprofessional.', 2),
  (59, 'C', 'Don''t bash the contractor; explain what warranties typically actually cover', TRUE, 'Honest framing. Reference: Module 12.', 3),
  (59, 'D', 'Recommend full replacement to avoid the issue', FALSE, 'Replacement isn''t always the right scope.', 4),
  (60, 'A', '24 hours after rain stops', FALSE, 'Industry standard is 48 hours.', 1),
  (60, 'B', '48 hours after rain stops', TRUE, 'Industry standard. Reference: Chapter 16, Module 3.', 2),
  (60, 'C', 'One week after rain stops', FALSE, 'One week is too long.', 3),
  (60, 'D', 'There is no standard', FALSE, 'Standard exists.', 4)
) AS v(question_number, answer_letter, answer_text, is_correct, explanation, display_order)
JOIN quizzes q ON q.is_final_exam = TRUE
JOIN quiz_questions qq ON qq.quiz_id = q.id AND qq.question_number = v.question_number;
